#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    int max_len = 1;
    int cur_len = 1;

    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            ++cur_len;
        } else {
            cur_len = 1;
        }
        if (cur_len > max_len) {
            max_len = cur_len;
        }
    }

    cout << max_len << "\n";

    return 0;
}
